// === NR 1.2.2 — MONTAR QUERY ===
// Transforma keywords do subtema em query de busca YouTube
// Usa keyword[0] (mais search-friendly que o nome completo)
// Salva contexto no staticData para nodes seguintes

const item = $input.first().json;

if (!item.subId) {
  return [{ json: { _vazio: true } }];
}

const keywords = item.keywords || [];
const query = keywords[0] || item.nome || '';

if (!query.trim()) {
  return [{ json: { _vazio: true, subId: item.subId } }];
}

const staticData = $getWorkflowStaticData('global');
staticData.currentSub = {
  subId: item.subId,
  nome: item.nome,
  keywords: item.keywords,
  is_onda: item.is_onda_entre_mercados || false
};

return [{ json: { query, subId: item.subId } }];

// === NR 1.2.2 — PROCESSAR BUSCA ===
// Extrai video IDs do resultado da busca YouTube
// Se sem resultados, marca _semVideos para tratar no Calcular Métricas

const response = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const sub = staticData.currentSub || {};

const items = response?.items || [];
const totalResults = parseInt(response?.pageInfo?.totalResults || '0');

if (items.length === 0) {
  return [{ json: {
    _semVideos: true,
    subId: sub.subId,
    totalResults,
    videoIds: ''
  } }];
}

const videoIds = items
  .map(r => r.id?.videoId)
  .filter(Boolean);

if (videoIds.length === 0) {
  return [{ json: {
    _semVideos: true,
    subId: sub.subId,
    totalResults,
    videoIds: ''
  } }];
}

return [{ json: {
  _semVideos: false,
  subId: sub.subId,
  totalResults,
  videoIds: videoIds.join(','),
  resultCount: videoIds.length
} }];

// === NR 1.2.2 — CALCULAR MÉTRICAS ===
// Computa índices de saturação e oportunidade
// Determina tipo_oportunidade e status do subtema
//
// Índice de Saturação (0-10):
//   Vídeos recentes 365d (0-3) + Canais únicos (0-3)
//   + Idade média (0-2) + Views top 20 (0-2)
//
// Tipo de Oportunidade:
//   direta (<2) | qualidade (2-5) | angulo (5-7.0) | saturado (≥7.0)

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const sub = staticData.currentSub || {};
const subId = sub.subId;

let buscaData;
try {
  buscaData = $('Processar Busca').first().json;
} catch(e) {
  buscaData = { _semVideos: true, totalResults: 0 };
}

const now = new Date();

// === CASO SEM VÍDEOS ===
if (buscaData._semVideos || !input.items || input.items.length === 0) {
  const totalResults = buscaData.totalResults || 0;
  return [{ json: {
    id: subId,
    volume_busca_est: totalResults,
    views_youtube_top20: 0,
    saturacao_videos_recentes: 0,
    saturacao_canais_unicos: 0,
    saturacao_idade_media_dias: null,
    indice_saturacao: 0,
    indice_oportunidade: 10,
    tipo_oportunidade: 'direta',
    is_demanda_silenciosa: totalResults > 10000,
    status: 'validado'
  } }];
}

// === PROCESSAR VÍDEOS ===
const videos = input.items || [];
const channelIds = new Set();
const viewsList = [];
let totalAgeDays = 0;
let recentCount = 0;

for (const v of videos) {
  const views = parseInt(v.statistics?.viewCount || '0');
  const publishedAt = new Date(v.snippet?.publishedAt || now);
  const ageDays = Math.floor((now - publishedAt) / (1000 * 60 * 60 * 24));

  channelIds.add(v.snippet?.channelId);
  viewsList.push(views);
  totalAgeDays += ageDays;

  if (ageDays <= 365) recentCount++;
}

viewsList.sort((a, b) => b - a);
const top20Views = viewsList.slice(0, 20).reduce((sum, v) => sum + v, 0);

const videoCount = videos.length;
const canaisUnicos = channelIds.size;
const idadeMediaDias = videoCount > 0
  ? Math.round(totalAgeDays / videoCount)
  : null;
const totalResults = buscaData.totalResults || 0;

// === ÍNDICE DE SATURAÇÃO (0-10) ===
let sat = 0;

// 1. Vídeos recentes — últimos 365 dias (0-3)
if (recentCount >= 21) sat += 3;
else if (recentCount >= 9) sat += 2.5;
else if (recentCount >= 4) sat += 1.5;
else if (recentCount >= 1) sat += 0.5;

// 2. Canais únicos (0-3)
if (canaisUnicos >= 16) sat += 3;
else if (canaisUnicos >= 9) sat += 2.5;
else if (canaisUnicos >= 4) sat += 1.5;
else if (canaisUnicos >= 2) sat += 0.5;

// 3. Idade média — mais novo = mais saturado (0-2)
if (idadeMediaDias !== null) {
  if (idadeMediaDias < 90) sat += 2;
  else if (idadeMediaDias < 180) sat += 1.5;
  else if (idadeMediaDias < 365) sat += 1;
  else if (idadeMediaDias < 730) sat += 0.5;
}

// 4. Views top 20 (0-2)
if (top20Views > 10000000) sat += 2;
else if (top20Views > 1000000) sat += 1.5;
else if (top20Views > 100000) sat += 1;
else if (top20Views > 10000) sat += 0.5;

const indiceSaturacao = Math.round(sat * 100) / 100;
const indiceOportunidade = Math.round((10 - indiceSaturacao) * 100) / 100;

// === TIPO DE OPORTUNIDADE ===
let tipoOportunidade;
if (indiceSaturacao < 2) {
  tipoOportunidade = 'direta';
} else if (indiceSaturacao < 5) {
  tipoOportunidade = 'qualidade';
} else if (indiceSaturacao < 7.0) {
  tipoOportunidade = 'angulo';
} else {
  tipoOportunidade = 'saturado';
}

const status = tipoOportunidade === 'saturado' ? 'saturado' : 'validado';

// === DEMANDA SILENCIOSA ===
const isDemandaSilenciosa = totalResults > 10000
  && recentCount <= 5
  && canaisUnicos <= 3;

return [{ json: {
  id: subId,
  volume_busca_est: totalResults,
  views_youtube_top20: top20Views,
  saturacao_videos_recentes: recentCount,
  saturacao_canais_unicos: canaisUnicos,
  saturacao_idade_media_dias: idadeMediaDias,
  indice_saturacao: indiceSaturacao,
  indice_oportunidade: indiceOportunidade,
  tipo_oportunidade: tipoOportunidade,
  is_demanda_silenciosa: isDemandaSilenciosa,
  status
} }];

// === NR 1.2.2 — Preparar Subtemas (TESTE: limite 3) ===
const subtemas = $('Buscar Subtemas').all().map(i => i.json);

const novos = subtemas.filter(s => s.status === 'novo');

if (novos.length === 0) {
  return [{ json: { _vazio: true, motivo: 'nenhum_subtema_novo' } }];
}

// TESTE: limitar a 70 subtemas
const limitados = novos.slice(0, 70);

return limitados.map(s => ({
  json: {
    subId: s.id,
    nome: s.nome,
    keywords: s.keywords || [],
    is_onda_entre_mercados: s.is_onda_entre_mercados || false
  }
}));

